// ======  CLOUDFLARE IMAGE HELPER ======
// Formate une URL d'image Cloudflare Images (format: https://imagedelivery.net/<accountHash>/<imageId>/<variant>)
// Si l'URL n'est pas Cloudflare Images, elle est retournée telle quelle.
// Variants Cloudflare recommandés : "thumbnail" (200x200), "card" (600x600), "public" (original)
function cfImg(url, variant) {
  if (!url || url.length < 10) return null;
  // Détecte une URL Cloudflare Images
  if (url.indexOf('imagedelivery.net') !== -1) {
    // Remplace le variant final dans l'URL
    // Format: https://imagedelivery.net/{accountHash}/{imageId}/{variant}
    return url.replace(/\/[^\/]+$/, '/' + (variant || 'public'));
  }
  return url; // URL externe (ibb.co, etc.) → retournée telle quelle
}

function getMainImg(p,vi){
  var v=p.variants&&p.variants[vi||0];
  if(v&&v.photos&&v.photos.length&&v.photos[0]&&v.photos[0].length>10)return cfImg(v.photos[0], 'card');
  if(p.photos&&p.photos.length&&p.photos[0]&&p.photos[0].length>10)return cfImg(p.photos[0], 'card');
  return null;
}
function getAllPhotos(p,vi){
  var v=p.variants&&p.variants[vi||0];
  var vp=v&&v.photos?v.photos.filter(function(x){return x&&x.length>10;}):[];
  var pp=p.photos?p.photos.filter(function(x){return x&&x.length>10;}):[];
  return vp.length?vp:pp;
}
