// ====== PWA — SERVICE WORKER ======
var swRegistration = null;
var newWorker = null;

function showUpdateBar() {
  localStorage.setItem('sw_update_pending', '1');
  document.getElementById('swUpdateBar').classList.add('show');
}

// Enregistrement du Service Worker
if ('serviceWorker' in navigator) {
  window.addEventListener('load', function() {
    navigator.serviceWorker.register('/sw.js').then(function(reg) {
      swRegistration = reg;
      console.log('[PWA] Service Worker enregistré:', reg.scope);

      // Cas 1 : un SW est déjà en attente dès le chargement (ex: onglet rouvert)
      if (reg.waiting && navigator.serviceWorker.controller) {
        newWorker = reg.waiting;
        showUpdateBar();
      }

      // Cas 2 : un nouveau SW vient de finir de s'installer
      reg.addEventListener('updatefound', function() {
        newWorker = reg.installing;
        if (!newWorker) return;
        newWorker.addEventListener('statechange', function() {
          if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
            showUpdateBar();
          }
        });
      });

      // Cas 3 : localStorage indique une mise à jour en attente (page rechargée sans clic)
      if (localStorage.getItem('sw_update_pending')) {
        setTimeout(function() {
          if (reg.waiting && navigator.serviceWorker.controller) {
            newWorker = reg.waiting;
            showUpdateBar();
          } else if (!reg.waiting) {
            // Le SW s'est déjà activé → nettoyer
            localStorage.removeItem('sw_update_pending');
          }
        }, 500);
      }

      // Vérification périodique des mises à jour (toutes les 60s)
      reg.update();
      setInterval(function() { reg.update(); }, 60000);

    }).catch(function(err) {
      console.warn('[PWA] Service Worker échec:', err);
    });

    // Quand le SW prend le contrôle (après SKIP_WAITING), recharge la page
    var refreshing = false;
    navigator.serviceWorker.addEventListener('controllerchange', function() {
      if (!refreshing) {
        refreshing = true;
        localStorage.removeItem('sw_update_pending');
        window.location.reload();
      }
    });
  });
}

function applySwUpdate() {
  if (newWorker) {
    newWorker.postMessage({ type: 'SKIP_WAITING' });
  }
  // La barre reste visible jusqu'au rechargement effectif de la page
}

// ====== PWA — INSTALLATION ======
var deferredPrompt = null;
var pwaInstalled = false;

// Vérifie si déjà installé (mode standalone)
if (window.matchMedia('(display-mode: standalone)').matches ||
    window.navigator.standalone === true) {
  pwaInstalled = true;
}

window.addEventListener('beforeinstallprompt', function(e) {
  e.preventDefault();
  deferredPrompt = e;

  // N'affiche la bannière du haut que si pas déjà fermée cette session
  if (!sessionStorage.getItem('pwa_closed')) {
    document.getElementById('pwaBar').classList.add('show');
    document.getElementById('mainNav').classList.add('below-pwa');
  }

  // Affiche TOUJOURS le bouton flottant FAB et le badge hero
  document.getElementById('pwaFab').classList.add('show');
  document.getElementById('pwaHeroBadge').classList.add('show');
});

// Clic sur le bouton "Installer" de la bannière du haut
document.getElementById('pwaBtnInstall').addEventListener('click', function() {
  triggerPwaInstall();
  closePwaBar();
});

function triggerPwaInstall() {
  if (deferredPrompt) {
    deferredPrompt.prompt();
    deferredPrompt.userChoice.then(function(result) {
      console.log('[PWA] Choix utilisateur:', result.outcome);
      if (result.outcome === 'accepted') {
        document.getElementById('pwaFab').classList.remove('show');
        document.getElementById('pwaHeroBadge').classList.remove('show');
      }
      deferredPrompt = null;
    });
  } else {
    // iOS ou navigateur sans prompt : guide l'utilisateur
    showToast('Sur iOS : appuyez sur Partager → "Sur l\'écran d\'accueil"', 'info');
  }
}

function closePwaBar() {
  document.getElementById('pwaBar').classList.remove('show');
  document.getElementById('mainNav').classList.remove('below-pwa');
  sessionStorage.setItem('pwa_closed', '1');
  // Le FAB reste visible même si on ferme la bannière
}

window.addEventListener('appinstalled', function() {
  closePwaBar();
  document.getElementById('pwaFab').classList.remove('show');
  document.getElementById('pwaHeroBadge').classList.remove('show');
  showToast('✅ Application installée avec succès !');
  pwaInstalled = true;
});

