function switchVarModal(pid,idx,el){
  curVar=idx;
  el.parentNode.querySelectorAll(".vchip").forEach(function(c){c.classList.remove("on");});
  el.classList.add("on");
  var p=state.products.find(function(x){return x.id===pid;});if(!p)return;
  var photos=getAllPhotos(p,idx);
  var mi=document.getElementById("mImg");if(mi&&photos.length)mi.src=photos[0];
  var tc=document.querySelector(".modal-thumbs");
  if(tc)tc.innerHTML=photos.length>1?photos.map(function(ph,i){return '<img class="mthumb'+(i===0?" on":"") +'" src="'+ph+'" onclick="switchImg(\''+ph+'\',this)" alt=""/>';}).join(""):"";
  updTotal(pid);
}
function switchImg(src,el){
  var m=document.getElementById("mImg");if(m)m.src=src;
  el.parentNode.querySelectorAll(".mthumb").forEach(function(t){t.classList.remove("on");});
  el.classList.add("on");
}
function closeModal(){document.getElementById("prodModal").classList.remove("open");document.body.style.overflow="";}
function chQty(d,pid){var i=document.getElementById("qty-"+pid);if(!i)return;i.value=Math.max(1,(parseInt(i.value)||1)+d);updTotal(pid);}
function updTotal(pid){var p=state.products.find(function(x){return x.id===pid;});if(!p)return;var q=parseInt(document.getElementById("qty-"+pid).value)||1;var el=document.getElementById("tot-"+pid);if(el)el.textContent=fmt(getPrice(p,q,curVar)*q)+" FCFA";}

function buildMsg(p,vi,qty,template){
  var v=p.variants&&p.variants[vi];
  var vt=v?" - "+v.name:"";
  var pr=getPrice(p,qty,vi);
  return encodeURIComponent(template.replace("{name}",p.name).replace("{variant}",vt).replace("{qty}",qty).replace("{unit}",p.unit||"piece").replace("{price}",fmt(pr)).replace("{total}",fmt(pr*qty)));
}
function orderWA(pid,vi,qty){
  var p=state.products.find(function(x){return x.id===pid;});if(!p)return;
  var wa=getFirstWaNum();
  window.open("https://wa.me/"+wa+"?text="+buildMsg(p,vi,qty,tx("waMsg")),"_blank");
}
function orderWAModal(pid){orderWA(pid,curVar,parseInt(document.getElementById("qty-"+pid).value)||1);}
function orderOrangeModal(pid){
  var p=state.products.find(function(x){return x.id===pid;});if(!p)return;
  var wa=getFirstWaNum();
  var qty=parseInt(document.getElementById("qty-"+pid).value)||1;
  window.open("https://wa.me/"+wa+"?text="+buildMsg(p,curVar,qty,tx("omMsg")),"_blank");
}

