// ====== TOAST ======
function showToast(msg,type){
  var t=document.getElementById("toast");
  t.textContent=msg;
  if(type==="err") t.style.borderColor="rgba(226,75,74,.4)";
  else if(type==="info") t.style.borderColor="rgba(74,144,226,.4)";
  else t.style.borderColor="rgba(201,168,76,.3)";
  t.classList.add("show");
  setTimeout(function(){t.classList.remove("show");},3500);
}

